import{c as s,Q as i,j as o,m as t}from"./chunks/framework.CdiUUa3G.js";const p=JSON.parse('{"title":"ADR-039 — Bidirectional cross-link contract: site panels ↔ mission cards","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-039.md","filePath":"adr/ADR-039.md"}'),a={name:"adr/ADR-039.md"};function n(r,e,c,d,l,u){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="adr-039-—-bidirectional-cross-link-contract-site-panels-↔-mission-cards" tabindex="-1">ADR-039 — Bidirectional cross-link contract: site panels ↔ mission cards <a class="header-anchor" href="#adr-039-—-bidirectional-cross-link-contract-site-panels-↔-mission-cards" aria-label="Permalink to &quot;ADR-039 — Bidirectional cross-link contract: site panels ↔ mission cards&quot;">​</a></h1><blockquote><p>Status · Accepted (closes RFC-012 OQ-4) Date · 2026-05-09 (back-filled from v0.4.0 implementation) Closes · RFC-012 OQ-4 (&quot;/mars ↔ /missions cross-link UX&quot;) TA anchor · §components/cross-routing Related ADRs · ADR-013 (History API routing), ADR-024 (Mission URL sharing), ADR-037 (shared surface-site type)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p><code>/mars</code> (and <code>/moon</code>) site panels show landing-site detail; <code>/missions</code> cards show full mission detail. Many entries appear in both — Curiosity is a Mars surface site AND a mission. RFC-012 OQ-4 asked: how do the two views cross-link without drifting?</p><p>Three failure modes worth designing against:</p><ol><li><strong>Drift</strong> — Curiosity&#39;s launch year is 2011 in <code>/missions</code>, but <code>/mars</code> accidentally says 2012 because two different overlay files describe the same thing. Schema should reject this.</li><li><strong>Lost context</strong> — user reads about Curiosity on <code>/mars</code>, clicks through to <code>/missions</code>, has no way back. URL contract should round-trip cleanly.</li><li><strong>Broken link</strong> — <code>/mars?site=curiosity</code> opens a panel; that panel says &quot;FULL MISSION CARD&quot; linking to <code>/missions?id=curiosity</code>; the mission then says &quot;ON THE SURFACE&quot; linking back to <code>/mars?site=curiosity</code>. Both directions must work; either-direction rot is invisible without explicit tests.</li></ol><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="field-name-mission-id" tabindex="-1">Field name: <code>mission_id</code> <a class="header-anchor" href="#field-name-mission-id" aria-label="Permalink to &quot;Field name: \`mission_id\`&quot;">​</a></h3><p>Every <code>/mars</code> and <code>/moon</code> site that corresponds to a <code>/missions</code> catalog entry carries a <code>mission_id</code> field referencing the mission&#39;s primary id. Validate-data enforces:</p><ul><li>If <code>mission_id</code> is set, it MUST exist in <code>static/data/missions/index.json</code> (validate-data treats unknown ids as a fail-closed error per ADR-019).</li><li>Editorial fields that appear in BOTH the site panel and the mission panel (mission name, launch date, agency) SHOULD be sourced from the mission entry first, with the site overlay only adding surface-specific details (landing coordinates, surface time, samples returned, capability unlocked).</li></ul><h3 id="forward-cross-link-—-site-→-mission" tabindex="-1">Forward cross-link — site → mission <a class="header-anchor" href="#forward-cross-link-—-site-→-mission" aria-label="Permalink to &quot;Forward cross-link — site → mission&quot;">​</a></h3><p>The site panel renders a chip / cross-link block titled &quot;FULL MISSION CARD&quot; (per UXS) when <code>mission_id</code> is set. Click navigates to <code>/missions?id=&lt;mission_id&gt;</code>. The mission panel opens pre-selected.</p><h3 id="reverse-cross-link-—-mission-→-surface" tabindex="-1">Reverse cross-link — mission → surface <a class="header-anchor" href="#reverse-cross-link-—-mission-→-surface" aria-label="Permalink to &quot;Reverse cross-link — mission → surface&quot;">​</a></h3><p>The mission panel renders a &quot;ON THE SURFACE&quot; chip when the corresponding mission id appears in either <code>mars-sites.json</code> or <code>moon-sites.json</code>. Click navigates to <code>/mars?site=&lt;id&gt;</code> or <code>/moon?site=&lt;id&gt;</code> (the resolver picks the body the site is on). The site panel opens pre-selected.</p><h3 id="url-contract" tabindex="-1">URL contract <a class="header-anchor" href="#url-contract" aria-label="Permalink to &quot;URL contract&quot;">​</a></h3><p>Both directions are URL-state-driven:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mars?site=curiosity</span></span>
<span class="line"><span>/moon?site=apollo11</span></span>
<span class="line"><span>/missions?id=curiosity</span></span></code></pre></div><p>URL is the source of truth — back/forward in the browser navigates exactly through the cross-link history. Bookmarking either deep link reopens the right panel.</p><h3 id="drift-guard" tabindex="-1">Drift guard <a class="header-anchor" href="#drift-guard" aria-label="Permalink to &quot;Drift guard&quot;">​</a></h3><p>E2e test <code>/mars</code> round-trip per RFC-012 §Decision criteria #3:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/mars?site=curiosity → click &quot;FULL MISSION CARD&quot;</span></span>
<span class="line"><span>  → /missions?id=curiosity (mission panel open + named &quot;Curiosity&quot;)</span></span>
<span class="line"><span>  → click &quot;ON THE SURFACE&quot;</span></span>
<span class="line"><span>  → /mars?site=curiosity (site panel open + named &quot;Curiosity&quot;)</span></span></code></pre></div><p>Same test exists for <code>/moon</code> round-trip with Apollo 11.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><ul><li><strong><code>mission_id</code> field</strong> keeps the cross-link explicit + machine-checkable (validate-data can verify every link before ship).</li><li><strong>URL state</strong> matches the existing routing contract (ADR-013 / ADR-024); no new mechanism needed.</li><li><strong>One-way display rule</strong> (&quot;editorial fields sourced from mission entry first&quot;) keeps the data flow obvious — mission JSON is canonical for shared fields; site overlay adds surface-only fields.</li><li><strong>E2e round-trip test</strong> catches drift early — if either chip stops rendering or routes wrong, CI breaks.</li></ul><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Embed the mission record in the site overlay</strong> (one big merged JSON per site) — rejected because mission updates would have to fan out to two places. Schema-validated <code>mission_id</code> reference is cheaper.</li><li><strong>Canonical mission JSON only, with site data as <code>surface: {…}</code> sub-object on missions</strong> — rejected because not every mission has a surface (orbiters, flybys); the surface-site catalogue would have nullable <code>surface</code> everywhere.</li><li><strong>No automatic reverse link</strong> (forward-only) — rejected because mission users want to know &quot;where on the surface did this land?&quot; without guessing the site id.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>One canonical place for shared fields (mission entry); site overlays add surface-only details.</li><li>URL contract round-trips cleanly; back/forward works.</li><li>E2e test catches cross-link rot.</li><li>Validate-data fails closed on unknown <code>mission_id</code> references.</li></ul><p><strong>Negative:</strong></p><ul><li>Site authors must remember to set <code>mission_id</code> for sites that have a corresponding mission — tracked by the e2e test (any new site without a <code>mission_id</code> for an existing mission would fail the round-trip if the cross-link is expected).</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li><code>src/types/surface-site.ts</code> — <code>SurfaceSite.mission_id?: string</code> (optional).</li><li><code>static/data/schemas/surface-site.schema.json</code> — <code>mission_id</code> as string, validated by <code>scripts/validate-data.ts</code> against <code>missions/index.json</code> ids.</li><li><code>src/lib/components/MissionCard.svelte</code> (or equivalent on <code>/missions</code> MissionPanel) — renders &quot;ON THE SURFACE&quot; chip when site found.</li><li><code>src/routes/mars/+page.svelte</code>, <code>src/routes/moon/+page.svelte</code> — render &quot;FULL MISSION CARD&quot; chip when <code>mission_id</code> set.</li><li>E2e: <code>tests/e2e/mars.spec.ts</code> covers Curiosity round-trip; <code>tests/e2e/moon.spec.ts</code> covers Apollo 11 round-trip.</li></ul>`,33)])])}const m=s(a,[["render",n]]);export{p as __pageData,m as default};
